        processor = try await PaymentProcessor(environment: .sandbox)
    }

    override func tearDown() {
        processor = nil
    }

    func testChargeSucceeds() async throws {
        let result = try await processor.charge(amount: 9.99, currency: .usd)
        XCTAssertTrue(result.isSuccessful)
        XCTAssertEqual(result.currency, .usd)
        XCTAssertGreaterThan(result.transactionId.count, 0)
    }

