        XCTAssertThrowsError(try await processor.charge(amount: 999999, currency: .usd)) { error in
            XCTAssertEqual(error as? PaymentError, .insufficientFunds)
        }
    }

    func testRefundRequiresValidTransaction() throws {
        let transaction = try XCTUnwrap(Transaction.lastCompleted)
        XCTAssertNoThrow(try processor.refund(transaction))
    }
}
